/*
 * retrokix landing — top-100 marquee ticker.
 *
 * Builds a horizontally-scrolling strip of the top-ranked games from
 * `window.GX_TOP_GAMES` (generated by scripts/build_top_games.py).
 * Each pill: <emoji> <Title> <Console>. Shuffled per page load so the
 * strip looks different on every visit. Animation is pure CSS — we
 * duplicate the list and translate-X infinitely for a seamless loop.
 * Pauses on hover; respects prefers-reduced-motion.
 */
(() => {
  const host = document.getElementById("gx-ticker");
  if (!host) return;
  const games = Array.isArray(window.GX_TOP_GAMES) ? window.GX_TOP_GAMES : [];
  if (!games.length) return;

  // Fisher–Yates shuffle (in-place on a copy).
  const shuffled = games.slice();
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = (Math.random() * (i + 1)) | 0;
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }

  const consoleColor = (slug) =>
    slug === "GBA" ? "gx-ticker__console--gba"
    : slug === "NES" ? "gx-ticker__console--nes"
    : "";

  const buildItem = (g) => {
    const item = document.createElement("span");
    item.className = "gx-ticker__item";
    item.innerHTML = `
      <span class="gx-ticker__emoji" aria-hidden="true">${g.e}</span>
      <span class="gx-ticker__title">${g.t}</span>
      <span class="gx-ticker__console ${consoleColor(g.c)}">${g.c}</span>
    `;
    return item;
  };

  const buildRow = () => {
    const row = document.createElement("div");
    row.className = "gx-ticker__row";
    shuffled.forEach((g) => row.appendChild(buildItem(g)));
    return row;
  };

  // Two identical rows side-by-side — CSS translates the track by 50%
  // for a seamless loop.
  const track = document.createElement("div");
  track.className = "gx-ticker__track";
  track.appendChild(buildRow());
  track.appendChild(buildRow());
  host.appendChild(track);

  // Honor reduced motion — kill the animation, leave the static list.
  if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) {
    track.style.animation = "none";
  }
})();
